parameters.jsCode:
// Parse Todoist tasks
const tasks = $('Fetch Todoist Tasks').all();
const taskList = tasks.map(t => {
  const j = t.json;
  return `- ${j.content}${j.due ? ' (Due: ' + j.due.date + ')' : ''}${j.priority > 1 ? ' [P' + j.priority + ']' : ''}`;
}).join('\n') || 'No tasks due today.';

// Parse Calendar Events
const calData = $('Fetch Calendar Events').first().json;
const events = (calData.items || []).map(e => {
  const start = e.start?.dateTime || e.start?.date || 'All day';
  const time = start.includes('T') ? new Date(start).toLocaleTimeString('en-US', {hour: '2-digit', minute:'2-digit'}) : 'All day';
  return `- ${time}: ${e.summary || 'Untitled event'}`;
}).join('\n') || 'No events scheduled today.';

// Parse Emails
const emailData = $('Fetch Unread Emails').first().json;
const emailCount = (emailData.messages || []).length;
const emailSummary = emailCount > 0 ? `${emailCount} unread email(s) waiting for your attention.` : 'Inbox is clear — no unread emails.';

// Parse Weather
const weather = $('Fetch Weather Forecast').first().json;
const current = weather.list?.[0];
const weatherSummary = current
  ? `${Math.round(current.main.temp)}°C, ${current.weather[0].description}. Feels like ${Math.round(current.main.feels_like)}°C. Humidity: ${current.main.humidity}%.`
  : 'Weather data unavailable.';
const city = weather.city?.name || 'your city';

// Parse News
const newsData = $('Fetch Top News').first().json;
const headlines = (newsData.articles || []).slice(0, 5).map((a, i) => `${i+1}. ${a.title} (${a.source?.name || 'Unknown'})`).join('\n') || 'No news headlines available.';

// Get preferences
const prefs = $('Set User Preferences').first().json;

return {
  json: {
    userName: prefs.userName,
    todayDate: prefs.todayDate,
    deliveryMethod: prefs.deliveryMethod,
    userPhone: prefs.userPhone,
    userEmail: prefs.userEmail,
    taskList,
    calendarEvents: events,
    emailSummary,
    weatherSummary,
    city,
    headlines,
    taskCount: tasks.length,
    eventCount: (calData.items || []).length
  }
};

const item = $input.item.json;
const agentOutput = item.output || item.text || item.response || 'Good morning! Your briefing is ready.';
return {
  json: {
    ...item,
    briefingText: agentOutput,
    briefingDate: new Date().toISOString().split('T')[0],
    briefingTimestamp: new Date().toISOString(),
    deliveryMethod: $('JS - Aggregate All Data').first().json.deliveryMethod,
    userPhone: $('JS - Aggregate All Data').first().json.userPhone,
    userEmail: $('JS - Aggregate All Data').first().json.userEmail,
    userName: $('JS - Aggregate All Data').first().json.userName
  }
};

